// // This module compares two 32-bit operands based on a three-bit operation code.
// It outputs a single binary result (res) indicating the condition defined by the operation code:
// - Equality when operation is 000
// - Less than when 010
// - Greater than for operation codes 101 and 110
// If an invalid operation code is presented, the result is set to an unknown state.
module top_module(
        input   wire [31:0]   op1,
        input   wire [31:0]   op2,
        input   wire [2:0]    operation,
        output  wire          res
    );reg comp_res;

    always @ *
    case (operation)
        3'b000: comp_res = (op1 ==  op2); 
        3'b010: comp_res = (op1 >   op2);
        3'b101, 
        3'b110: comp_res = (op1 <   op2);
        default: comp_res = 1'bx;
    endcase

    assign res = comp_res;

endmodule

